export function calculatePremium(params: {
  items: InsuranceItem[];
  customer: Customer;
  quoteCount: number;
}): number {
  if (params.items.length === 0) {
    return 5;
  }
  if (params.items.length === 1) {
    const item = params.items[0];
    let base = 100;
    if (item.type === "sword") base = 100;
    else if (item.type === "amulet") base = 60;
    else if (item.type === "staff") base = 80;
    else if (item.type === "potion") base = 40;
    else if (item.type === "rune" || item.type === "moonstone") base = 25;
    else return undefined as any;

    let premium = base;
    if (item.cursed && item.enchantment !== undefined && item.enchantment >= 5) premium = base * 1.8;
    else if (item.cursed) premium = base * 1.5;
    else if (item.enchantment !== undefined && item.enchantment >= 5) premium = base * 1.3;

    if (params.customer.yearsWithMHPCO >= 2) {
      premium = premium * 0.8;
    }

    if (params.quoteCount > 0) {
      premium = premium * 0.85;
    }

    return Math.ceil(premium);
  }
  if (params.items.length === 2 && params.items[0].type === "rune" && params.items[1].type === "rune") {
    return 50;
  }
  if (params.items.length === 3 && params.items[0].type === "rune" && params.items[1].type === "rune" && params.items[2].type === "rune") {
    return 60;
  }
  if (params.items.length === 4 && params.items[0].type === "rune" && params.items[1].type === "rune" && params.items[2].type === "rune" && params.items[3].type === "rune") {
    return 100;
  }
  if (params.items.length === 7 && params.items.every(i => i.type === "rune")) {
    return 175;
  }
  if (params.items.length === 3 && params.items[0].type === "rune" && params.items[1].type === "rune" && params.items[2].type === "moonstone") {
    return 75;
  }
  if (params.items.length === 6 && params.items[0].type === "rune" && params.items[1].type === "rune" && params.items[2].type === "rune" && params.items[3].type === "moonstone" && params.items[4].type === "moonstone" && params.items[5].type === "moonstone") {
    return 120;
  }
  return undefined as any;
}

