import { calculatePremium, processClaim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Base Premium Calculation", () => {
    it("should return 5 G for empty item list (only processing fee)", () => {
      expect(calculatePremium({ items: [], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(5);
    });
    it("should return 100 G base premium for a sword", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(100);
    });
    it("should return 60 G base premium for an amulet", () => {
      expect(calculatePremium({ items: [{ type: "amulet" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(60);
    });
    it("should return 80 G base premium for a staff", () => {
      expect(calculatePremium({ items: [{ type: "staff" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(80);
    });
    it("should return 40 G base premium for a potion", () => {
      expect(calculatePremium({ items: [{ type: "potion" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(40);
    });
    it("should return 25 G base premium for a single rune", () => {
      expect(calculatePremium({ items: [{ type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(25);
    });
    it("should return 25 G base premium for a single moonstone", () => {
      expect(calculatePremium({ items: [{ type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(25);
    });
    it("should return 50 G base premium for 2 runes (no block)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(50);
    });
    it("should return 60 G base premium for 3 runes (block applies)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(60);
    });
    it("should return 100 G base premium for 4 runes (no block - requires exactly 3)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(100);
    });
    it("should return 175 G base premium for 7 runes (2 blocks of 3 + 1)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(175);
    });
    it("should return 75 G base premium for 2 runes + 1 moonstone (different types, no block)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(75);
    });
    it("should return 120 G base premium for 3 runes + 3 moonstones (two separate blocks)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(120);
    });
  });

  describe("Premium Modifiers", () => {
    it("should apply cursed surcharge of 50% on cursed sword's base premium", () => {
      expect(calculatePremium({ items: [{ type: "sword", cursed: true }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(150);
    });
    it("should apply high-enchantment surcharge of 30% on sword with enchantment 5", () => {
      expect(calculatePremium({ items: [{ type: "sword", enchantment: 5 }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(130);
    });
    it("should apply both surcharges on cursed sword with enchantment 5", () => {
      expect(calculatePremium({ items: [{ type: "sword", cursed: true, enchantment: 5 }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(195);
    });
    it("should apply loyalty discount of 20% for customer with >= 2 years", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 2 }, quoteCount: 0 })).toBe(80);
    });
    it("should apply first insurance surcharge of 10%", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(110);
    });
    it("should apply follow-up contract discount of 15% on second quote", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 1 })).toBe(95);
    });
    it("should add 5 G processing fee to every premium", () => {
      expect(calculatePremium({ items: [], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(5);
    });
  });

  describe("Modifier Scope on Multi-Item Policies", () => {
    it("should apply cursed surcharge only to cursed item's base premium, not policy total", () => {
      expect(calculatePremium({ items: [{ type: "sword", cursed: true }, { type: "amulet" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(210);
    });
    it("should apply policy-wide modifiers (loyalty, first insurance, follow-up) to sum of all item base premiums", () => {
      expect(calculatePremium({ items: [{ type: "sword" }, { type: "amulet" }], customer: { yearsWithMHPCO: 2 }, quoteCount: 0 })).toBe(136);
    });
  });

  describe("Rounding", () => {
    it("should round premium up (197.5 G -> 198 G) in MHPCO's favor", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0, roundingTest: 197.5 })).toBe(198);
    });
    it("should round payout down (350.5 G -> 350 G) in MHPCO's favor", () => {
      const policy: any = { items: [{ type: "sword", insuranceValue: 1000 }], insuranceSum: 1000, cap: 2000, remainingCap: 2000 };
      const result = processClaim({ policy, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 350.5 }] } });
      expect(result.payout).toBe(350);
    });
  });

  describe("Premium Integration Examples", () => {
    it("should calculate premium 165 G for newcomer with cursed sword (enchantment 3)", () => {
      expect(calculatePremium({ items: [{ type: "sword", cursed: true, enchantment: 3 }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(165);
    });
    it("should calculate premium 160 G for long-standing customer's second contract with cursed sword (enchantment 7)", () => {
      expect(calculatePremium({ items: [{ type: "sword", cursed: true, enchantment: 7 }], customer: { yearsWithMHPCO: 3 }, quoteCount: 1 })).toBe(160);
    });
  });

  describe("Claim Processing - Standard Reimbursement", () => {
    it("should return payout 400 G for regular sword (steel, enchantment 3), damage 500 G", () => {
      const policy: any = { items: [{ type: "sword", enchantment: 3, insuranceValue: 1000 }], insuranceSum: 1000, cap: 2000, remainingCap: 2000 };
