import { calculatePremium, processClaim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Base Premium Calculation", () => {
    it("should return 5 G for empty item list (only processing fee)", () => {
      expect(calculatePremium({ items: [], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(5);
    });
    it("should return 100 G base premium for a sword", () => {
      expect(calculatePremium({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(100);
    });
    it("should return 60 G base premium for an amulet", () => {
      expect(calculatePremium({ items: [{ type: "amulet" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(60);
    });
    it("should return 80 G base premium for a staff", () => {
      expect(calculatePremium({ items: [{ type: "staff" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(80);
    });
    it("should return 40 G base premium for a potion", () => {
      expect(calculatePremium({ items: [{ type: "potion" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(40);
    });
    it("should return 25 G base premium for a single rune", () => {
      expect(calculatePremium({ items: [{ type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(25);
    });
    it("should return 25 G base premium for a single moonstone", () => {
      expect(calculatePremium({ items: [{ type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(25);
    });
    it("should return 50 G base premium for 2 runes (no block)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(50);
    });
    it("should return 60 G base premium for 3 runes (block applies)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(60);
    });
    it("should return 100 G base premium for 4 runes (no block - requires exactly 3)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(100);
    });
    it("should return 175 G base premium for 7 runes (2 blocks of 3 + 1)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(175);
    });
    it("should return 75 G base premium for 2 runes + 1 moonstone (different types, no block)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(75);
    });
    it("should return 120 G base premium for 3 runes + 3 moonstones (two separate blocks)", () => {
      expect(calculatePremium({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }], customer: { yearsWithMHPCO: 0 }, quoteCount: 0 })).toBe(120);
    });
  });
});

import { describe, it, expect } from "vitest";

const ITEM_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export interface Customer {
  yearsWithMHPCO: number;
}

export interface InsuranceItem {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface ClaimDamage {
  itemType: string;
  amount: number;
}

export interface Policy {
  items: InsuranceItem[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

export function calculatePremium(params: {
  items: InsuranceItem[];
  customer: Customer;
  quoteCount: number;
}): number {
  if (params.items.length === 0) {
    return 5;
  }

  const basePremiums = params.items.map((item) => {
    if (item.type in BASE_PREMIUMS) {
      return BASE_PREMIUMS[item.type];
    }
    throw new Error(`Unknown item type: ${item.type}`);
  });

  let totalBasePremium = 0;
  const itemPremiums: number[] = [];

  for (let i = 0; i < params.items.length; i++) {
    const item = params.items[i];
    let premium = basePremiums[i];

    if (item.cursed) {
      premium = premium * 1.5;
    }
    if (item.enchantment !== undefined && item.enchantment >= 5) {
      premium = premium * 1.3;
    }

    itemPremiums.push(premium);
    totalBasePremium += premium;
  }

  const hasBlocks = params.items.length >= 3;
  const runeCount = params.items.filter((i) => i.type === "rune").length;
  const moonstoneCount = params.items.filter((i) => i.type === "moonstone").length;

  const runeBlocks = Math.floor(runeCount / 3);
  const moonstoneBlocks = Math.floor(moonstoneCount / 3);
  const blockDiscount = runeBlocks * 5 + moonstoneBlocks * 5;

  totalBasePremium -= blockDiscount;

  if (params.customer.yearsWithMHPCO >= 2) {
    totalBasePremium = totalBasePremium * 0.8;
  }

  totalBasePremium = totalBasePremium * 1.1;

  if (params.quoteCount > 0) {
    totalBasePremium = totalBasePremium * 0.85;
  }

  totalBasePremium = totalBasePremium + 5;

  return Math.ceil(totalBasePremium);
}

export function processClaim(params: {
  policy: Policy;
  incident: {
    cause: string;
    damages: ClaimDamage[];
  };
}): { payout: number; remainingCap: number } {
  let totalPayout = 0;
  const damages = params.incident.damages;

  for (const damage of damages) {
    let amount = damage.amount;

    const item = params.policy.items.find((i) => i.type === damage.itemType);
    if (!item) {
      throw new Error(`Damage to item not in policy: ${damage.itemType}`);
    }

